1	import bcrypt from 'bcryptjs';
2	import jwt from 'jsonwebtoken';
3	import crypto from 'crypto';
4	import { config } from '../../config';
5	import prisma from '../../lib/prisma';
6	import { encrypt, maskPhone } from '../../lib/encryption';
7	import { logger } from '../../lib/logger';
8	import { JwtPayload } from '../../types';
9	import { RegisterInput, LoginInput } from './auth.schema';
10	import { Role } from '@prisma/client';
11	
12	export class AuthService {
13	  async register(input: RegisterInput) {
14	    const existing = await prisma.user.findUnique({ where: { username: input.username } });
15	    if (existing) {
16	      throw Object.assign(new Error('Username already taken'), { statusCode: 409, code: 'CONFLICT' });
17	    }
18	
19	    const salt = crypto.randomBytes(16).toString('hex');
20	    const passwordHash = await bcrypt.hash(input.password + salt, 12);
21	
22	    const phoneEncrypted = input.phone ? encrypt(input.phone) : null;
23	    const phoneMasked = input.phone ? maskPhone(input.phone) : null;
24	
25	    const user = await prisma.user.create({
26	      data: {
27	        username: input.username,
28	        passwordHash,
29	        salt,
30	        displayName: input.displayName,
31	        role: (input.role as Role) || 'GUEST',
32	        phoneEncrypted,
33	        phoneMasked,
34	      },
35	      select: {
36	        id: true,
37	        username: true,
38	        displayName: true,
39	        role: true,
40	        phoneMasked: true,
41	        createdAt: true,
42	      },
43	    });
44	
45	    // Create initial trust score
46	    await prisma.trustScore.create({
47	      data: { userId: user.id, score: 50.0 },
48	    });
49	
50	    logger.info({ userId: user.id, username: user.username }, 'User registered');
51	
52	    const token = this.generateToken(user.id, user.username, user.role);
53	    return { user, token };
54	  }
55	
56	  async login(input: LoginInput) {
57	    const user = await prisma.user.findUnique({
58	      where: { username: input.username },
59	      select: {
60	        id: true,
61	        username: true,
62	        displayName: true,
63	        role: true,
64	        passwordHash: true,
65	        salt: true,
66	        phoneMasked: true,
67	        isActive: true,
68	      },
69	    });
70	
71	    if (!user || !user.isActive) {
72	      throw Object.assign(new Error('Invalid credentials'), { statusCode: 401, code: 'INVALID_CREDENTIALS' });
73	    }
74	
75	    const valid = await bcrypt.compare(input.password + user.salt, user.passwordHash);
76	    if (!valid) {
77	      throw Object.assign(new Error('Invalid credentials'), { statusCode: 401, code: 'INVALID_CREDENTIALS' });
78	    }
79	
80	    logger.info({ userId: user.id, username: user.username }, 'User logged in');
81	
82	    const token = this.generateToken(user.id, user.username, user.role);
83	    const { passwordHash, salt, ...safeUser } = user;
84	    return { user: safeUser, token };
85	  }
86	
87	  async getCurrentUser(userId: number) {
88	    const user = await prisma.user.findUnique({
89	      where: { id: userId },
90	      select: {
91	        id: true,
92	        username: true,
93	        displayName: true,
94	        role: true,
95	        phoneMasked: true,
96	        isActive: true,
97	        createdAt: true,
98	      },
99	    });
100	
101	    if (!user || !user.isActive) {
102	      throw Object.assign(new Error('User not found'), { statusCode: 404, code: 'NOT_FOUND' });
103	    }
104	
105	    return user;
106	  }
107	
108	  private generateToken(userId: number, username: string, role: Role): string {
109	    const payload: JwtPayload = { userId, username, role };
110	    return jwt.sign(payload, config.jwt.secret, { expiresIn: config.jwt.expiresIn });
111	  }
112	}
