16	export class ModerationService {
17	  async fileReport(input: FileReportInput, reporterId: number) {
18	    // Prevent duplicate reports from same user on same content
19	    const existing = await prisma.report.findFirst({
20	      where: {
21	        reporterId,
22	        contentType: input.contentType,
23	        contentId: input.contentId,
24	        status: { in: ['PENDING', 'IN_REVIEW'] },
25	      },
26	    });
27	    if (existing) businessError('DUPLICATE', 'You have already reported this content', 409);
28	
29	    const report = await prisma.report.create({
30	      data: {
31	        reporterId,
32	        contentType: input.contentType,
33	        contentId: input.contentId,
34	        reviewId: input.reviewId ?? null,
35	        reason: input.reason,
36	        status: 'PENDING',
37	      },
38	    });
39	
40	    // If content is a review, flag it
41	    if (input.contentType === 'REVIEW' && input.reviewId) {
42	      await prisma.review.update({
43	        where: { id: input.reviewId },
44	        data: { status: 'FLAGGED' },
45	      });
46	    }
47	
48	    logger.info({ reportId: report.id, reporterId, contentType: input.contentType, contentId: input.contentId }, 'Report filed');
49	    return report;
50	  }
