166	  async fileAppeal(input: FileAppealInput, userId: number) {
167	    const action = await prisma.moderationAction.findUnique({
168	      where: { id: input.moderationActionId },
169	    });
170	    if (!action) businessError('NOT_FOUND', 'Moderation action not found', 404);
171	
172	    // One appeal per user per moderation action
173	    const existing = await prisma.appeal.findFirst({
174	      where: { userId, moderationActionId: input.moderationActionId },
175	    });
176	    if (existing) businessError('DUPLICATE', 'You have already appealed this action', 409);
177	
178	    const appeal = await prisma.appeal.create({
179	      data: {
180	        userId,
181	        moderationActionId: input.moderationActionId,
182	        userStatement: input.userStatement,
183	        status: 'PENDING',
184	      },
185	    });
186	
187	    logger.info({ appealId: appeal.id, userId, moderationActionId: input.moderationActionId }, 'Appeal filed');
188	    return appeal;
