191	  async listAppeals(status?: string, page = 1, pageSize = 20) {
192	    const skip = (page - 1) * pageSize;
193	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
194	    const where: any = {};
195	    if (status) where.status = status;
196	
197	    const [items, total] = await Promise.all([
198	      prisma.appeal.findMany({
199	        where,
200	        skip,
201	        take: pageSize,
202	        include: {
203	          user: { select: { id: true, displayName: true } },
204	          moderationAction: {
205	            include: {
206	              moderator: { select: { id: true, displayName: true } },
207	              report: { select: { id: true, contentType: true, contentId: true } },
208	            },
209	          },
210	        },
211	        orderBy: { createdAt: 'desc' },
212	      }),
213	      prisma.appeal.count({ where }),
214	    ]);
215	
216	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
217	  }
218	
219	  async resolveAppeal(appealId: number, input: ResolveAppealInput) {
220	    const appeal = await prisma.appeal.findUnique({
221	      where: { id: appealId },
222	      include: {
223	        moderationAction: {
224	          include: { report: { include: { review: true } } },
225	        },
226	      },
227	    });
228	    if (!appeal) businessError('NOT_FOUND', 'Appeal not found', 404);
229	
230	    // State machine: PENDING/IN_REVIEW → UPHELD/OVERTURNED/IN_REVIEW
231	    const validTransitions: Record<string, string[]> = {
232	      PENDING: ['IN_REVIEW', 'UPHELD', 'OVERTURNED'],
233	      IN_REVIEW: ['UPHELD', 'OVERTURNED'],
234	    };
235	    const allowed = validTransitions[appeal!.status] ?? [];
236	    if (!allowed.includes(input.status)) {
237	      businessError('INVALID_STATE', `Cannot transition from ${appeal!.status} to ${input.status}`, 422);
238	    }
239	
240	    const updated = await prisma.$transaction(async (tx) => {
241	      const resolvedAt = ['UPHELD', 'OVERTURNED'].includes(input.status) ? new Date() : null;
242	
243	      const result = await tx.appeal.update({
244	        where: { id: appealId },
245	        data: {
246	          status: input.status as any,
247	          arbitrationNotes: input.arbitrationNotes ?? null,
248	          outcome: input.outcome ?? null,
249	          resolvedAt,
250	        },
251	      });
252	
253	      // On OVERTURNED: restore the review if the action was HIDE or REMOVE
254	      if (input.status === 'OVERTURNED') {
255	        const originalAction = appeal!.moderationAction.action;
256	        const reviewId = appeal!.moderationAction.report.reviewId;
257	        if (reviewId && (originalAction === 'HIDE' || originalAction === 'REMOVE')) {
258	          await tx.review.update({
259	            where: { id: reviewId },
260	            data: { status: 'ACTIVE' },
261	          });
262	        }
263	      }
264	
265	      return result;
266	    });
267	
268	    logger.info({ appealId, status: input.status }, 'Appeal resolved');
269	    return updated;
270	  }
