272	  async addSensitiveWord(input: AddSensitiveWordInput) {
273	    const normalized = input.word.toLowerCase();
274	    const word = await prisma.sensitiveWord.upsert({
275	      where: { word: normalized },
276	      create: { word: normalized, category: input.category ?? null },
277	      update: { category: input.category ?? null },
278	    });
279	
280	    // Invalidate cache so next content filter reload picks up the new word
281	    cache.delete('sensitive_words');
282	
283	    logger.info({ wordId: word.id, word: word.word }, 'Sensitive word added');
284	    return word;
285	  }
286	
287	  async listSensitiveWords(page = 1, pageSize = 50) {
288	    const skip = (page - 1) * pageSize;
289	    const [items, total] = await Promise.all([
290	      prisma.sensitiveWord.findMany({
291	        skip,
292	        take: pageSize,
293	        orderBy: { word: 'asc' },
294	      }),
295	      prisma.sensitiveWord.count(),
296	    ]);
297	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
298	  }
299	
300	  async deleteSensitiveWord(id: number) {
301	    const word = await prisma.sensitiveWord.findUnique({ where: { id } });
302	    if (!word) businessError('NOT_FOUND', 'Sensitive word not found', 404);
303	
304	    await prisma.sensitiveWord.delete({ where: { id } });
305	    cache.delete('sensitive_words');
306	
307	    logger.info({ wordId: id }, 'Sensitive word removed');
308	    return { deleted: true };
309	  }
310	}
