1	import { Role } from '@prisma/client';
2	import { Request } from 'express';
3	
4	export interface JwtPayload {
5	  userId: number;
6	  username: string;
7	  role: Role;
8	  iat?: number;
9	  exp?: number;
10	}
11	
12	export interface AuthenticatedRequest extends Request {
13	  user?: JwtPayload;
14	}
15	
16	export interface PaginationQuery {
17	  page?: string;
18	  pageSize?: string;
19	}
20	
21	export interface PaginatedResponse<T> {
22	  items: T[];
23	  total: number;
24	  page: number;
25	  pageSize: number;
26	  totalPages: number;
27	}
28	
29	export interface ApiResponse<T = unknown> {
30	  success: boolean;
31	  data?: T;
32	  error?: {
33	    code: string;
34	    message: string;
35	    details?: unknown;
36	  };
37	}
38	
39	export function paginate(page?: string | number, pageSize?: string | number) {
40	  const p = Math.max(1, parseInt(String(page || '1'), 10));
41	  const ps = Math.min(100, Math.max(1, parseInt(String(pageSize || '20'), 10)));
42	  return { page: p, pageSize: ps, skip: (p - 1) * ps, take: ps };
43	}
44	
45	export function successResponse<T>(data: T): ApiResponse<T> {
46	  return { success: true, data };
47	}
48	
49	export function errorResponse(code: string, message: string, details?: unknown): ApiResponse {
50	  return { success: false, error: { code, message, details } };
51	}
