1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import { RateTaskInput, AdminAdjustInput } from './trust.schema';
4	
5	function businessError(code: string, message: string, statusCode: number): never {
6	  throw Object.assign(new Error(message), { statusCode, code });
7	}
8	
9	// Credit delta map: rating → credit change
10	const CREDIT_DELTA: Record<number, number> = {
11	  5: 2,
12	  4: 1,
13	  3: 0,
14	  2: -1,
15	  1: -2,
16	};
17	
18	function buildExplanation(rating: number, delta: number, taskId: number): string {
19	  if (delta > 0) return `Received ${rating}★ rating on task #${taskId}: +${delta} trust credit`;
20	  if (delta < 0) return `Received ${rating}★ rating on task #${taskId}: ${delta} trust credit`;
21	  return `Received ${rating}★ rating on task #${taskId}: no trust change`;
22	}
23	
24	export class TrustService {
25	  async getScore(userId: number) {
26	    return prisma.trustScore.findUnique({ where: { userId } });
27	    return score ?? { userId, score: 50 };
28	  }
29	
30	  async getHistory(userId: number, page: number, pageSize: number) {
31	    const skip = (page - 1) * pageSize;
32	    const [items, total] = await Promise.all([
33	      prisma.creditHistory.findMany({
34	        where: { userId },
35	        orderBy: { createdAt: 'desc' },
36	        skip,
37	        take: pageSize,
38	      }),
39	      prisma.creditHistory.count({ where: { userId } }),
40	    ]);
41	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
42	  }
43	
44	  async getLeaderboard(limit: number = 10) {
45	    return prisma.trustScore.findMany({
46	      orderBy: { score: 'desc' },
47	      take: limit,
48	      include: { user: { select: { id: true, username: true, displayName: true } } },
49	    });
50	  }
51	
52	  async getAllScores() {
53	    return prisma.trustScore.findMany({
54	      orderBy: { score: 'desc' },
54	      include: { user: { select: { id: true, username: true, displayName: true, role: true } } },
55	    });
56	  }
57	
58	  async rateTask(input: RateTaskInput, raterId: number) {
59	    // Prevent self-rating
60	    if (input.rateeId === raterId) {
61	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
62	    }
63	
64	    // Unique per rater+task
65	    const existing = await prisma.taskRating.findUnique({
66	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
67	    });
68	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
69	
70	    // Verify ratee exists
71	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
72	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
73	
74	    const delta = CREDIT_DELTA[input.rating] ?? 0;
75	    const explanation = buildExplanation(input.rating, delta, input.taskId);
76	
77	    await prisma.$transaction(async (tx) => {
78	      // Create rating record
79	      await tx.taskRating.create({
80	        data: {
81	          raterId,
82	          rateeId: input.rateeId,
83	          taskId: input.taskId,
84	          rating: input.rating,
85	          comment: input.comment ?? null,
86	        },
87	      });
88	
89	      if (delta !== 0) {
90	        // Upsert trust score, clamp 0-100
91	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
92	        const currentScore = Number(current?.score ?? 50);
93	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
94	
95	        await tx.trustScore.upsert({
96	          where: { userId: input.rateeId },
97	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
98	          update: { score: newScore, lastUpdated: new Date() },
99	        });
100	
101	        // Credit history
102	        await tx.creditHistory.create({
103	          data: {
104	            userId: input.rateeId,
105	            changeAmount: delta,
106	            reason: `Task rating from user #${raterId}`,
107	            sourceType: 'TASK_RATING',
108	            sourceId: input.taskId,
109	            explanation,
110	          },
111	        });
112	      }
113	    });
114	
115	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
116	    return { message: 'Rating submitted', delta, explanation };
117	  }
118	
119	  async adminAdjust(input: AdminAdjustInput, adminId: number) {
120	    const user = await prisma.user.findUnique({ where: { id: input.userId } });
121	    if (!user) businessError('NOT_FOUND', 'User not found', 404);
122	
123	    const current = await prisma.trustScore.findUnique({ where: { userId: input.userId } });
124	    const currentScore = Number(current?.score ?? 50);
125	    const newScore = Math.max(0, Math.min(100, currentScore + input.changeAmount));
126	
127	    await prisma.$transaction(async (tx) => {
128	      await tx.trustScore.upsert({
129	        where: { userId: input.userId },
130	        create: { userId: input.userId, score: newScore, lastUpdated: new Date() },
131	        update: { score: newScore, lastUpdated: new Date() },
132	      });
133	
134	        const direction = input.changeAmount > 0 ? `+${input.changeAmount}` : `${input.changeAmount}`;
135	        await tx.creditHistory.create({
136	          data: {
137	            userId: input.userId,
138	            changeAmount: input.changeAmount,
139	            reason: input.reason,
140	            sourceType: 'ADMIN_ADJUSTMENT',
141	            sourceId: adminId,
142	            explanation: `Admin adjustment by #${adminId}: ${direction} (${input.reason})`,
143	          },
144	        });
145	    });
146	
147	    logger.info({ adminId, targetUserId: input.userId, changeAmount: input.changeAmount }, 'Trust score adjusted by admin');
148	    return { userId: input.userId, previousScore: currentScore, newScore };
149	  }
150	}
151	
152	export const trustService = new TrustService();
