        .post('/api/trust/adjust')
        .set('Authorization', `Bearer ${guestToken}`)
        .send({ userId: 2, changeAmount: 10, reason: 'Unauthorized attempt' })
        .expect(403);
      expect(res.body.success).toBe(false);
    });
  });
});
