31	// ─── Nightly KPI aggregation (2 AM) ─────────────────────────────
32	registerJob('nightly-kpi-aggregation', '0 2 * * *', async () => {
33	  const prisma = (await import('./prisma')).default;
34	
35	  const yesterday = new Date();
36	  yesterday.setDate(yesterday.getDate() - 1);
37	  yesterday.setHours(0, 0, 0, 0);
38	  const today = new Date(yesterday);
39	  today.setDate(today.getDate() + 1);
40	
41	  // DAU: count distinct users who generated rate limit log entries yesterday
42	  const dauRows = await prisma.rateLimitLog.groupBy({
43	    by: ['userId'],
44	    where: { createdAt: { gte: yesterday, lt: today } },
45	  });
46	  const dau = dauRows.length;
47	
48	  // Inventory turnover proxy: total ISSUE qty yesterday / avg onHand
49	  const issueAgg = await prisma.inventoryLedger.aggregate({
50	    _sum: { quantity: true },
51	    where: { movementType: 'ISSUE', createdAt: { gte: yesterday, lt: today } },
52	  });
53	  const totalIssues = issueAgg._sum.quantity ?? 0;
54	
55	  const avgStockResult = await prisma.stockLevel.aggregate({ _avg: { onHand: true } });
56	  const avgStock = Number(avgStockResult._avg.onHand ?? 1);
57	  const conversionRate = avgStock > 0 ? totalIssues / avgStock : 0;
58	
59	  await prisma.kpiDaily.upsert({
60	    where: { date: yesterday },
61	    create: {
62	      date: yesterday,
63	      dau,
64	      conversionRate,
65	      aov: 0,
66	      repurchaseRate: 0,
67	      refundRate: 0,
68	    },
69	    update: { dau, conversionRate },
70	  });
71	
72	  logger.info({ date: yesterday.toISOString().slice(0, 10), dau, conversionRate }, 'KPI aggregation completed');
73	});
74	
75	// ─── Nightly average daily usage update (3 AM) ──────────────────
76	registerJob('nightly-avg-usage-update', '0 3 * * *', async () => {
77	  const prisma = (await import('./prisma')).default;
78	
79	  const thirtyDaysAgo = new Date();
80	  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
81	
82	  // Aggregate ISSUE quantities per (itemId, fromLocationId, lotId) over last 30 days
83	  const grouped = await prisma.inventoryLedger.groupBy({
84	    by: ['itemId', 'fromLocationId', 'lotId'],
85	    _sum: { quantity: true },
86	    where: { movementType: 'ISSUE', createdAt: { gte: thirtyDaysAgo } },
87	  });
88	
89	  let updated = 0;
90	  for (const row of grouped) {
91	    if (row.fromLocationId === null) continue;
92	    const avgDailyUsage = (row._sum.quantity ?? 0) / 30;
93	
94	    await prisma.stockLevel.updateMany({
95	      where: {
96	        itemId: row.itemId,
97	        locationId: row.fromLocationId,
98	        lotId: row.lotId ?? null,
99	      },
100	      data: { avgDailyUsage },
101	    });
102	    updated++;
103	  }
104	
105	  logger.info({ updated }, 'Avg daily usage update completed');
106	});
107	
108	// ─── Nightly low-stock reorder check (4 AM) ────────────────────
109	registerJob('nightly-low-stock-reorder', '0 4 * * *', async () => {
110	  const prisma = (await import('./prisma')).default;
111	
112	  const lowStockItems = await prisma.stockLevel.findMany({
113	    where: {
114	      onHand: { lte: prisma.stockLevel.fields.safetyThreshold },
115	    },
116	    include: {
117	      item: { select: { id: true, name: true, sku: true } },
118	      location: { select: { id: true, name: true } },
119	    },
120	  });
121	
122	  // Workaround: raw query for column-to-column comparison
123	  const lowStock = await prisma.$queryRaw<Array<{
124	    id: number;
125	    itemId: number;
126	    locationId: number;
127	    onHand: number;
128	    safetyThreshold: number;
129	    itemName: string;
130	    itemSku: string;
131	    locationName: string;
132	  }>>`
133	    SELECT sl.id, sl.item_id AS itemId, sl.location_id AS locationId,
134	           sl.on_hand AS onHand, sl.safety_threshold AS safetyThreshold,
135	           i.name AS itemName, i.sku AS itemSku, l.name AS locationName
136	    FROM stock_levels sl
137	    JOIN items i ON i.id = sl.item_id
138	    JOIN locations l ON l.id = sl.location_id
139	    WHERE sl.on_hand <= sl.safety_threshold
140	  `;
141	
142	  if (lowStock.length > 0) {
143	    logger.warn(
144	      { count: lowStock.length, items: lowStock.map(s => ({ sku: s.itemSku, location: s.locationName, onHand: s.onHand, threshold: s.safetyThreshold })) },
145	      `Low-stock alert: ${lowStock.length} item(s) below safety threshold`
146	    );
147	  } else {
148	    logger.info('Low-stock check: all items above safety thresholds');
149	  }
150	});
151	
152	// ─── Cache cleanup every 30 minutes ─────────────────────────────
153	registerJob('cache-cleanup', '*/30 * * * *', async () => {
154	  const { cache } = await import('./cache');
155	  cache.cleanup();
156	  logger.info('Cache cleanup completed');
157	});
