1	import { stringify } from 'csv-stringify/sync';
2	import ExcelJS from 'exceljs';
3	
4	export interface ExportOptions {
5	  username: string;
6	  timestamp: string;
7	}
8	
9	export function exportToCsv(
10	  data: Record<string, unknown>[],
11	  columns: string[],
12	  options: ExportOptions
13	): string {
14	  const watermark = `# Exported by: ${options.username} | Timestamp: ${options.timestamp}`;
15	  const csvContent = stringify(data, {
16	    header: true,
17	    columns,
18	  });
19	  return `${watermark}\n${csvContent}`;
20	}
21	
22	export async function exportToExcel(
23	  data: Record<string, unknown>[],
24	  columns: string[],
25	  sheetName: string,
26	  options: ExportOptions
27	): Promise<Buffer> {
28	  const workbook = new ExcelJS.Workbook();
29	  workbook.creator = options.username;
30	  workbook.created = new Date(options.timestamp);
31	
32	  const sheet = workbook.addWorksheet(sheetName);
33	
34	  sheet.columns = columns.map((col) => ({
35	    header: col,
36	    key: col,
37	    width: 20,
38	  }));
39	
40	  data.forEach((row) => sheet.addRow(row));
41	
42	  // Watermark in header/footer
43	  sheet.headerFooter.oddHeader = `&L${options.username}&R${options.timestamp}`;
44	  sheet.headerFooter.oddFooter = `&LHARBOROPS CONFIDENTIAL&RPage &P of &N`;
45	
46	  // Style header row
47	  const headerRow = sheet.getRow(1);
48	  headerRow.font = { bold: true };
49	  headerRow.fill = {
50	    type: 'pattern',
51	    pattern: 'solid',
52	    fgColor: { argb: 'FF1E3A5F' },
53	  };
54	  headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
55	
56	  return Buffer.from(await workbook.xlsx.writeBuffer());
57	}
