59	  async rateTask(input: RateTaskInput, raterId: number) {
60	    // Prevent self-rating
61	    if (input.rateeId === raterId) {
62	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
63	    }
64	
65	    // Validate interaction exists
66	    const interaction = await prisma.serviceInteraction.findUnique({
67	      where: { id: input.taskId },
68	    });
69	    if (!interaction) {
70	      businessError('INTERACTION_NOT_FOUND', 'Service interaction not found', 404);
71	    }
72	
73	    // Validate interaction is completed
74	    if (interaction!.status !== 'COMPLETED') {
75	      businessError('INTERACTION_NOT_COMPLETED', 'Can only rate completed interactions', 422);
76	    }
77	
78	    // Validate rater and ratee are both participants
79	    const participantIds = new Set([interaction!.requesterId, interaction!.providerId]);
80	    if (!participantIds.has(raterId) || !participantIds.has(input.rateeId)) {
81	      businessError('NOT_PARTICIPANT', 'Rater and ratee must both be participants of this interaction', 403);
82	    }
83	
84	    // Unique per rater+task
85	    const existing = await prisma.taskRating.findUnique({
86	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
87	    });
88	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
89	
90	    // Verify ratee exists
91	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
92	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
93	
94	    const delta = CREDIT_DELTA[input.rating] ?? 0;
95	    const explanation = buildExplanation(input.rating, delta, input.taskId);
96	
97	    await prisma.$transaction(async (tx) => {
98	      // Create rating record
99	      await tx.taskRating.create({
100	        data: {
101	          raterId,
102	          rateeId: input.rateeId,
103	          taskId: input.taskId,
104	          rating: input.rating,
105	          comment: input.comment ?? null,
106	        },
107	      });
108	
109	      if (delta !== 0) {
110	        // Upsert trust score, clamp 0-100
111	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
112	        const currentScore = Number(current?.score ?? 50);
113	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
114	
115	        await tx.trustScore.upsert({
116	          where: { userId: input.rateeId },
117	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
118	          update: { score: newScore, lastUpdated: new Date() },
119	        });
120	
121	        // Credit history
122	        await tx.creditHistory.create({
123	          data: {
124	            userId: input.rateeId,
125	            changeAmount: delta,
126	            reason: `Task rating from user #${raterId}`,
127	            sourceType: 'TASK_RATING',
128	            sourceId: input.taskId,
129	            explanation,
130	          },
131	        });
132	      }
133	    });
134	
135	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
136	    return { message: 'Rating submitted', delta, explanation };
137	  }
