139	  async adminAdjust(input: AdminAdjustInput, adminId: number) {
140	    const user = await prisma.user.findUnique({ where: { id: input.userId } });
141	    if (!user) businessError('NOT_FOUND', 'User not found', 404);
142	
143	    const current = await prisma.trustScore.findUnique({ where: { userId: input.userId } });
144	    const currentScore = Number(current?.score ?? 50);
145	    const newScore = Math.max(0, Math.min(100, currentScore + input.changeAmount));
146	
147	    await prisma.$transaction(async (tx) => {
148	      await tx.trustScore.upsert({
149	        where: { userId: input.userId },
