159	          reason: input.reason,
160	          sourceType: 'ADMIN_ADJUSTMENT',
161	          sourceId: adminId,
162	          explanation: `Admin adjustment by #${adminId}: ${direction} (${input.reason})`,
163	        },
164	      });
165	    });
166	
167	    logger.info({ adminId, targetUserId: input.userId, changeAmount: input.changeAmount }, 'Trust score adjusted by admin');
