1	import { Response, NextFunction } from 'express';
2	import jwt from 'jsonwebtoken';
3	import { config } from '../config';
4	import { AuthenticatedRequest, JwtPayload, errorResponse } from '../types';
5	import { Role } from '@prisma/client';
6	
7	export function authenticate(req: AuthenticatedRequest, res: Response, next: NextFunction): void {
8	  const header = req.headers.authorization;
9	  if (!header || !header.startsWith('Bearer ')) {
10	    res.status(401).json(errorResponse('UNAUTHORIZED', 'Missing or invalid authorization header'));
11	    return;
12	  }
13	
14	  const token = header.slice(7);
15	  try {
16	    const payload = jwt.verify(token, config.jwt.secret) as JwtPayload;
17	    req.user = payload;
18	    next();
19	  } catch (err) {
20	    res.status(401).json(errorResponse('TOKEN_INVALID', 'Invalid or expired token'));
21	  }
22	}
23	
24	export function authorize(...roles: Role[]) {
25	  return (req: AuthenticatedRequest, res: Response, next: NextFunction): void => {
26	    if (!req.user) {
27	      res.status(401).json(errorResponse('UNAUTHORIZED', 'Authentication required'));
28	      return;
29	    }
30	    if (roles.length > 0 && !roles.includes(req.user.role)) {
31	      res.status(403).json(errorResponse('FORBIDDEN', 'Insufficient permissions'));
32	      return;
33	    }
34	    next();
35	  };
36	}
