1	import { describe, it, expect, beforeAll } from 'vitest';
2	import { api, loginAs, demoUsers, getInteractionId } from './helpers';
3	
4	describe('Trust / Credit API', () => {
5	  let adminToken: string;
6	  let guestToken: string;
7	  let hostToken: string;
8	  let clerkToken: string;
9	
10	  let hostUserId: number;
11	  let clerkUserId: number;
12	  let completedInteractionId: number;
13	  let inProgressInteractionId: number;
14	  let nonParticipantInteractionId: number;
15	
16	  beforeAll(async () => {
17	    [adminToken, guestToken, hostToken, clerkToken] = await Promise.all([
18	      loginAs(demoUsers.admin.username, demoUsers.admin.password),
19	      loginAs(demoUsers.guest.username, demoUsers.guest.password),
20	      loginAs(demoUsers.host.username, demoUsers.host.password),
21	      loginAs(demoUsers.clerk.username, demoUsers.clerk.password),
22	    ]);
23	
24	    // Get user IDs for rating targets
25	    const [hostMe, clerkMe] = await Promise.all([
26	      api.get('/api/auth/me').set('Authorization', `Bearer ${hostToken}`),
27	      api.get('/api/auth/me').set('Authorization', `Bearer ${clerkToken}`),
28	    ]);
29	    hostUserId = hostMe.body.data.id;
30	    clerkUserId = clerkMe.body.data.id;
31	
32	    // Get seeded interaction IDs
33	    [completedInteractionId, inProgressInteractionId, nonParticipantInteractionId] = await Promise.all([
34	      getInteractionId('guest', 'host', 'COMPLETED'),
35	      getInteractionId('guest', 'clerk', 'IN_PROGRESS'),
36	      getInteractionId('manager', 'host', 'COMPLETED'),
37	    ]);
38	  });
39	
40	  // ─── Score retrieval ──────────────────────────────────────────
41	
42	  describe('Score retrieval', () => {
43	    it('GET /api/trust/score returns score for authenticated user', async () => {
44	      const res = await api
45	        .get('/api/trust/score')
46	        .set('Authorization', `Bearer ${guestToken}`)
47	        .expect(200);
48	      expect(res.body.success).toBe(true);
49	      expect(res.body.data).toHaveProperty('score');
50	      expect(Number(res.body.data.score)).toBeGreaterThanOrEqual(0);
51	      expect(Number(res.body.data.score)).toBeLessThanOrEqual(100);
52	    });
53	
54	    it('GET /api/trust/history returns credit history', async () => {
55	      const res = await api
56	        .get('/api/trust/history')
57	        .set('Authorization', `Bearer ${guestToken}`)
58	        .expect(200);
59	      expect(res.body.success).toBe(true);
60	      expect(Array.isArray(res.body.data.items)).toBe(true);
61	    });
62	
63	    it('GET /api/trust/leaderboard returns top users', async () => {
64	      const res = await api
65	        .get('/api/trust/leaderboard')
66	        .set('Authorization', `Bearer ${guestToken}`)
67	        .expect(200);
68	      expect(res.body.success).toBe(true);
69	      expect(Array.isArray(res.body.data)).toBe(true);
70	    });
71	  });
72	
73	  // ─── Rating tasks ─────────────────────────────────────────────
74	
75	  describe('Rating tasks', () => {
76	    it('POST /api/trust/rate requires authentication (401)', async () => {
77	      await api
78	        .post('/api/trust/rate')
79	        .send({ rateeId: 2, taskId: 1, rating: 5 })
80	        .expect(401);
81	    });
82	
83	    it('POST /api/trust/rate rates a completed interaction successfully', async () => {
84	      const res = await api
85	        .post('/api/trust/rate')
86	        .set('Authorization', `Bearer ${guestToken}`)
87	        .send({ rateeId: hostUserId, taskId: completedInteractionId, rating: 5 })
88	        .expect(201);
89	      expect(res.body.success).toBe(true);
90	      expect(res.body.data).toHaveProperty('delta');
91	    });
92	
93	    it('POST /api/trust/rate prevents duplicate rating on same task (409)', async () => {
94	      const res = await api
95	        .post('/api/trust/rate')
96	        .set('Authorization', `Bearer ${guestToken}`)
97	        .send({ rateeId: hostUserId, taskId: completedInteractionId, rating: 4 })
98	        .expect(409);
99	      expect(res.body.success).toBe(false);
100	    });
101	
102	    it('POST /api/trust/rate rejects nonexistent interaction (404)', async () => {
103	      const res = await api
104	        .post('/api/trust/rate')
105	        .set('Authorization', `Bearer ${guestToken}`)
106	        .send({ rateeId: hostUserId, taskId: 999999999, rating: 5 })
107	        .expect(404);
108	      expect(res.body.success).toBe(false);
109	      expect(res.body.error.code).toBe('INTERACTION_NOT_FOUND');
110	    });
111	
112	    it('POST /api/trust/rate rejects non-completed interaction (422)', async () => {
113	      const res = await api
114	        .post('/api/trust/rate')
115	        .set('Authorization', `Bearer ${guestToken}`)
116	        .send({ rateeId: clerkUserId, taskId: inProgressInteractionId, rating: 4 })
117	        .expect(422);
118	      expect(res.body.success).toBe(false);
119	      expect(res.body.error.code).toBe('INTERACTION_NOT_COMPLETED');
120	    });
121	
122	    it('POST /api/trust/rate rejects when user is not a participant (403)', async () => {
123	      const res = await api
124	        .post('/api/trust/rate')
125	        .set('Authorization', `Bearer ${guestToken}`)
126	        .send({ rateeId: hostUserId, taskId: nonParticipantInteractionId, rating: 5 })
127	        .expect(403);
128	      expect(res.body.success).toBe(false);
129	      expect(res.body.error.code).toBe('NOT_PARTICIPANT');
130	    });
131	  });
132	
133	  // ─── Admin operations ─────────────────────────────────────────
134	
135	  describe('Admin operations', () => {
136	    it('POST /api/trust/adjust allows admin to adjust score directly', async () => {
137	      const res = await api
138	        .post('/api/trust/adjust')
139	        .set('Authorization', `Bearer ${adminToken}`)
140	        .send({ userId: 2, changeAmount: 10, reason: 'Manual boost for testing' })
141	        .expect(200);
142	      expect(res.body.success).toBe(true);
143	      expect(res.body.data).toHaveProperty('newScore');
144	    });
145	
146	    it('GET /api/trust/admin/scores returns all scores for admin', async () => {
147	      const res = await api
148	        .get('/api/trust/admin/scores')
149	        .set('Authorization', `Bearer ${adminToken}`)
150	        .expect(200);
151	      expect(res.body.success).toBe(true);
152	      expect(Array.isArray(res.body.data)).toBe(true);
153	    });
154	
155	    it('POST /api/trust/adjust by non-admin returns 403', async () => {
156	      const res = await api
157	        .post('/api/trust/adjust')
158	        .set('Authorization', `Bearer ${guestToken}`)
159	        .send({ userId: 2, changeAmount: 10, reason: 'Unauthorized attempt' })
160	        .expect(403);
161	      expect(res.body.success).toBe(false);
162	    });
163	  });
164	});
