27	async function resolveItemId(input: { itemId?: number; barcode?: string }): Promise<number> {
28	  if (input.barcode) {
29	    const item = await prisma.item.findUnique({ where: { barcode: input.barcode } });
30	    if (!item) businessError('BARCODE_NOT_FOUND', `No item found for barcode: ${input.barcode}`, 400);
31	    if (input.itemId && input.itemId !== item!.id) {
32	      businessError('BARCODE_MISMATCH', 'Barcode does not match the provided itemId', 400);
33	    }
34	    return item!.id;
35	  }
36	  if (input.itemId) return input.itemId;
37	  businessError('MISSING_ITEM', 'Either itemId or barcode is required', 400);
38	}
