52	  private generateRefNum(type: 'RCV' | 'ISS' | 'TRF' | 'STC' | 'ADJ'): string {
53	    const yyyymmdd = new Date().toISOString().slice(0, 10).replace(/-/g, '');
54	    const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
55	    return `${type}-${yyyymmdd}-${rand}`;
56	  }
