58	  private buildLedgerWhere(query: LedgerQuery) {
59	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
60	    const where: any = {};
61	
62	    if (query.itemId) where.itemId = parseInt(query.itemId, 10);
63	    if (query.vendorId) where.vendorId = parseInt(query.vendorId, 10);
64	    if (query.lotId) where.lotId = parseInt(query.lotId, 10);
65	    if (query.movementType) where.movementType = query.movementType;
66	
67	    if (query.locationId) {
68	      const locId = parseInt(query.locationId, 10);
69	      where.OR = [{ fromLocationId: locId }, { toLocationId: locId }];
70	    }
71	
72	    if (query.startDate || query.endDate) {
73	      const dateFilter: Record<string, Date> = {};
74	      if (query.startDate) dateFilter.gte = new Date(query.startDate);
75	      if (query.endDate) dateFilter.lte = new Date(query.endDate);
76	      where.createdAt = dateFilter;
77	    }
78	
79	    return where;
80	  }
