83	  private async applyStockCountAdjustments(
84	    tx: any,
85	    stockCountId: number,
86	    locationId: number,
87	    initiatedBy: number,
88	    lines: Array<{ id: number; itemId: number; lotId: number | null; varianceQty: number }>,
89	    approvedBy: number | null
90	  ): Promise<void> {
91	    for (const line of lines) {
92	      if (line.varianceQty === 0) continue;
93	
94	      // Find the stock level by matching itemId + locationId + lotId
95	      const stockLevel = await tx.stockLevel.findFirst({
96	        where: { itemId: line.itemId, locationId, lotId: line.lotId },
97	      });
98	
99	      if (stockLevel) {
100	        await tx.stockLevel.update({
101	          where: { id: stockLevel.id },
102	          data: { onHand: { increment: line.varianceQty } },
103	        });
104	      }
105	
106	      await tx.inventoryLedger.create({
107	        data: {
108	          itemId: line.itemId,
109	          lotId: line.lotId,
110	          toLocationId: locationId,
111	          movementType: 'STOCK_COUNT',
112	          quantity: line.varianceQty,
113	          referenceNumber: this.generateRefNum('STC'),
114	          performedBy: initiatedBy,
115	          approvedBy,
116	          notes: `Stock count adjustment (count id: ${stockCountId})`,
117	        },
118	      });
119	    }
120	  }
