254	  async receive(input: ReceiveInput, performedBy: number) {
255	    const itemId = await resolveItemId(input);
256	    const item = await prisma.item.findUnique({ where: { id: itemId } });
257	    if (!item) businessError('NOT_FOUND', 'Item not found', 404);
258	    if (item!.isLotControlled && !input.lotNumber) {
259	      businessError('LOT_REQUIRED', 'Lot number required for lot-controlled item', 422);
260	    }
261	
262	    let lotId: number | null = null;
263	    if (input.lotNumber) {
264	      const lot = await prisma.lot.upsert({
265	        where: { itemId_lotNumber: { itemId, lotNumber: input.lotNumber } },
266	        create: {
267	          itemId,
268	          lotNumber: input.lotNumber,
269	          expirationDate: input.expirationDate ? new Date(input.expirationDate) : null,
270	        },
271	        update: {},
272	      });
273	      lotId = lot.id;
274	    }
275	
276	    // Upsert stock level using findFirst + create/update for reliable null lotId handling
277	    const existingLevel = await prisma.stockLevel.findFirst({
278	      where: { itemId, locationId: input.locationId, lotId },
279	    });
280	
281	    if (existingLevel) {
282	      await prisma.stockLevel.update({
283	        where: { id: existingLevel.id },
284	        data: { onHand: { increment: input.quantity } },
285	      });
286	    } else {
287	      await prisma.stockLevel.create({
288	        data: {
289	          itemId,
290	          locationId: input.locationId,
291	          lotId,
292	          onHand: input.quantity,
293	          safetyThreshold: config.inventory.defaultSafetyThreshold,
294	          avgDailyUsage: 0,
295	        },
296	      });
297	    }
298	
299	    const ledgerEntry = await prisma.inventoryLedger.create({
300	      data: {
301	        itemId,
302	        lotId,
303	        toLocationId: input.locationId,
304	        movementType: 'RECEIVING',
305	        quantity: input.quantity,
306	        unitCostUsd: input.unitCostUsd ?? null,
307	        vendorId: input.vendorId,
308	        packSize: input.packSize ?? null,
309	        deliveryDatetime: input.deliveryDatetime ? new Date(input.deliveryDatetime) : null,
310	        referenceNumber: this.generateRefNum('RCV'),
311	        performedBy,
312	        notes: input.notes ?? null,
313	      },
314	      include: LEDGER_INCLUDE,
315	    });
316	
317	    logger.info({ ledgerId: ledgerEntry.id, itemId, qty: input.quantity }, 'Stock received');
318	    return ledgerEntry;
319	  }
