360	  async transfer(input: TransferInput, performedBy: number) {
361	    if (input.fromLocationId === input.toLocationId) {
362	      businessError('INVALID_TRANSFER', 'Source and destination locations must be different', 422);
363	    }
364	
365	    const itemId = await resolveItemId(input);
366	    const item = await prisma.item.findUnique({ where: { id: itemId } });
367	    if (!item) businessError('NOT_FOUND', 'Item not found', 404);
368	    if (item!.isLotControlled && !input.lotId) {
369	      businessError('LOT_REQUIRED', 'Lot ID required for lot-controlled item', 422);
370	    }
371	
372	    const ledgerEntry = await prisma.$transaction(async (tx) => {
373	      const source = await tx.stockLevel.findFirst({
374	        where: { itemId, locationId: input.fromLocationId, lotId: input.lotId ?? null },
375	      });
376	      if (!source) {
377	        businessError('NOT_FOUND', 'Source stock level not found', 404);
378	      }
379	      if (source!.onHand < input.quantity) {
380	        businessError('INSUFFICIENT_STOCK', `Insufficient stock: ${source!.onHand} available, ${input.quantity} requested`, 422);
381	      }
382	
383	      await tx.stockLevel.update({
384	        where: { id: source!.id },
385	        data: { onHand: { decrement: input.quantity } },
386	      });
387	
388	      const destExisting = await tx.stockLevel.findFirst({
389	        where: { itemId, locationId: input.toLocationId, lotId: input.lotId ?? null },
390	      });
391	
392	      if (destExisting) {
393	        await tx.stockLevel.update({
394	          where: { id: destExisting.id },
395	          data: { onHand: { increment: input.quantity } },
396	        });
397	      } else {
398	        await tx.stockLevel.create({
399	          data: {
400	            itemId,
401	            locationId: input.toLocationId,
402	            lotId: input.lotId ?? null,
403	            onHand: input.quantity,
404	            safetyThreshold: config.inventory.defaultSafetyThreshold,
405	            avgDailyUsage: 0,
406	          },
407	        });
408	      }
409	
410	      return tx.inventoryLedger.create({
411	        data: {
412	          itemId,
413	          lotId: input.lotId ?? null,
414	          fromLocationId: input.fromLocationId,
415	          toLocationId: input.toLocationId,
416	          movementType: 'TRANSFER',
417	          quantity: input.quantity,
418	          referenceNumber: this.generateRefNum('TRF'),
419	          performedBy,
420	          notes: input.notes ?? null,
421	        },
422	        include: LEDGER_INCLUDE,
423	      });
424	    });
425	
426	    logger.info({ ledgerId: ledgerEntry.id, itemId, qty: input.quantity }, 'Stock transferred');
427	    return ledgerEntry;
428	  }
