489	      return tx.stockCount.findUnique({
490	        where: { id: count.id },
491	        include: {
492	          location: true,
493	          initiator: { select: { displayName: true } },
494	          lines: {
495	            include: {
496	              item: { select: { name: true, sku: true } },
