507	  async updateLines(stockCountId: number, input: UpdateLinesInput) {
508	    const stockCount = await prisma.stockCount.findUnique({
509	      where: { id: stockCountId },
510	      include: {
511	        lines: {
512	          include: { item: { select: { unitPrice: true } } },
513	        },
514	      },
515	    });
516	    if (!stockCount) businessError('NOT_FOUND', 'Stock count not found', 404);
517	    if (stockCount!.status !== 'DRAFT') {
518	      businessError('INVALID_STATE', 'Stock count lines can only be updated in DRAFT status', 422);
519	    }
520	
521	    for (const { lineId, countedQty } of input.lines) {
522	      const existing = stockCount!.lines.find((l) => l.id === lineId);
523	      if (!existing) businessError('NOT_FOUND', `Stock count line ${lineId} not found`, 404);
524	
525	      const varianceQty = countedQty - existing!.systemQty;
526	      const variancePct =
527	        existing!.systemQty === 0
528	          ? null
529	          : (Math.abs(varianceQty) / existing!.systemQty) * 100;
530	      const varianceUsd =
531	        existing!.item.unitPrice !== null
532	          ? Math.abs(varianceQty) * Number(existing!.item.unitPrice)
533	          : null;
534	
535	      await prisma.stockCountLine.update({
536	        where: { id: lineId },
537	        data: { countedQty, varianceQty, variancePct, varianceUsd },
538	      });
539	    }
540	
541	    return prisma.stockCount.findUnique({
542	      where: { id: stockCountId },
543	      include: {
544	        lines: {
545	          include: {
546	            item: { select: { name: true, sku: true } },
547	            lot: { select: { lotNumber: true } },
548	          },
549	        },
550	      },
551	    });
552	  }
