554	  async finalizeStockCount(stockCountId: number) {
555	    const stockCount = await prisma.stockCount.findUnique({
556	      where: { id: stockCountId },
557	      include: { lines: true },
558	    });
559	    if (!stockCount) businessError('NOT_FOUND', 'Stock count not found', 404);
560	    if (stockCount!.status !== 'DRAFT') {
561	      businessError('INVALID_STATE', 'Only DRAFT stock counts can be finalized', 422);
562	    }
563	
564	    const lines = stockCount!.lines;
565	    const totalSystemQty = lines.reduce((s, l) => s + l.systemQty, 0);
566	    const totalAbsVarianceQty = lines.reduce((s, l) => s + Math.abs(l.varianceQty), 0);
567	    const totalVarianceUsd = lines.reduce((s, l) => s + (l.varianceUsd ? Number(l.varianceUsd) : 0), 0);
568	    const overallVariancePct =
569	      totalSystemQty === 0 ? 0 : (totalAbsVarianceQty / totalSystemQty) * 100;
570	
571	    const needsApproval =
572	      overallVariancePct > config.inventory.varianceApprovalPct ||
573	      totalVarianceUsd > config.inventory.varianceApprovalUsd;
574	
575	    if (needsApproval) {
576	      return prisma.stockCount.update({
577	        where: { id: stockCountId },
578	        data: {
579	          status: 'PENDING_APPROVAL',
580	          variancePct: overallVariancePct,
581	          varianceUsd: totalVarianceUsd,
582	        },
583	        include: { lines: true, location: true },
584	      });
585	    }
586	
587	    // Auto-approve
588	    await prisma.$transaction(async (tx) => {
589	      await this.applyStockCountAdjustments(
590	        tx,
591	        stockCountId,
592	        stockCount!.locationId,
593	        stockCount!.initiatedBy,
594	        lines,
595	        null
596	      );
597	      await tx.stockCount.update({
598	        where: { id: stockCountId },
599	        data: {
600	          status: 'APPROVED',
601	          variancePct: overallVariancePct,
602	          varianceUsd: totalVarianceUsd,
603	          completedAt: new Date(),
604	        },
605	      });
606	    });
607	
608	    return prisma.stockCount.findUnique({
609	      where: { id: stockCountId },
610	      include: { lines: true, location: true },
611	    });
612	  }
