614	  async approveStockCount(stockCountId: number, approvedBy: number) {
615	    const stockCount = await prisma.stockCount.findUnique({
616	      where: { id: stockCountId },
617	      include: { lines: true },
618	    });
619	    if (!stockCount) businessError('NOT_FOUND', 'Stock count not found', 404);
620	    if (stockCount!.status !== 'PENDING_APPROVAL') {
621	      businessError('INVALID_STATE', 'Only PENDING_APPROVAL stock counts can be approved', 422);
622	    }
623	
624	    await prisma.$transaction(async (tx) => {
625	      await this.applyStockCountAdjustments(
626	        tx,
