8	async function generateKpiSummary(): Promise<{ data: Record<string, unknown>[]; columns: string[] }> {
9	  const kpis = await prisma.kpiDaily.findMany({ orderBy: { date: 'desc' }, take: 30 });
10	  const columns = ['date', 'dau', 'conversionRate', 'aov', 'repurchaseRate', 'refundRate'];
11	  const data = kpis.map((k) => ({
12	    date: k.date.toISOString().slice(0, 10),
13	    dau: k.dau,
14	    conversionRate: Number(k.conversionRate),
15	    aov: Number(k.aov),
16	    repurchaseRate: Number(k.repurchaseRate),
17	    refundRate: Number(k.refundRate),
18	  }));
19	  return { data, columns };
20	}
21	
22	async function generateReviewEfficiency(): Promise<{ data: Record<string, unknown>[]; columns: string[] }> {
23	  const reports = await prisma.reportReviewEfficiency.findMany({ orderBy: { date: 'desc' }, take: 30 });
24	  const columns = ['date', 'avgModerationTimeHrs', 'flaggedCount', 'resolvedCount', 'appealRate'];
25	  const data = reports.map((r) => ({
26	    date: r.date.toISOString().slice(0, 10),
27	    avgModerationTimeHrs: Number(r.avgModerationTimeHrs),
28	    flaggedCount: r.flaggedCount,
29	    resolvedCount: r.resolvedCount,
30	    appealRate: Number(r.appealRate),
31	  }));
32	  return { data, columns };
33	}
34	
35	async function generateInventorySnapshot(): Promise<{ data: Record<string, unknown>[]; columns: string[] }> {
36	  const stocks = await prisma.stockLevel.findMany({
37	    include: {
38	      item: { select: { name: true, sku: true, category: true } },
39	      location: { select: { name: true } },
40	    },
41	  });
42	  const columns = ['sku', 'itemName', 'category', 'location', 'onHand', 'safetyThreshold', 'avgDailyUsage'];
43	  const data = stocks.map((s) => ({
44	    sku: s.item.sku,
45	    itemName: s.item.name,
46	    category: s.item.category,
47	    location: s.location.name,
48	    onHand: s.onHand,
49	    safetyThreshold: s.safetyThreshold,
50	    avgDailyUsage: Number(s.avgDailyUsage),
51	  }));
52	  return { data, columns };
53	}
54	
55	const generators: Record<string, () => Promise<{ data: Record<string, unknown>[]; columns: string[] }>> = {
56	  KPI_SUMMARY: generateKpiSummary,
57	  REVIEW_EFFICIENCY: generateReviewEfficiency,
58	  INVENTORY_SNAPSHOT: generateInventorySnapshot,
59	};
