61	export async function processScheduledReport(reportId: number) {
62	  const report = await prisma.scheduledReport.findUnique({
63	    where: { id: reportId },
64	    include: { requester: { select: { username: true } } },
65	  });
66	  if (!report) throw Object.assign(new Error('Report not found'), { statusCode: 404, code: 'NOT_FOUND' });
67	
68	  // Mark as PROCESSING
69	  await prisma.scheduledReport.update({
70	    where: { id: reportId },
71	    data: { status: 'PROCESSING' },
72	  });
73	
74	  try {
75	    const generator = generators[report.reportType];
76	    if (!generator) throw new Error(`Unknown report type: ${report.reportType}`);
77	
78	    const { data, columns } = await generator();
79	    const timestamp = new Date().toISOString();
80	    const options = { username: report.requester.username, timestamp };
81	
82	    // Determine format from filePath hint or default to csv
83	    const format = report.reportType.toLowerCase().includes('excel') ? 'excel' : 'csv';
84	
85	    const reportsDir = path.join(config.upload.dir, 'reports');
86	    if (!fs.existsSync(reportsDir)) {
87	      fs.mkdirSync(reportsDir, { recursive: true });
88	    }
89	
90	    let filePath: string;
91	    if (format === 'excel') {
92	      const buffer = await exportToExcel(data, columns, report.reportType, options);
93	      filePath = path.join(reportsDir, `report_${reportId}.xlsx`);
94	      fs.writeFileSync(filePath, buffer);
95	    } else {
96	      const csv = exportToCsv(data, columns, options);
97	      filePath = path.join(reportsDir, `report_${reportId}.csv`);
98	      fs.writeFileSync(filePath, csv);
99	    }
100	
101	    const updated = await prisma.scheduledReport.update({
102	      where: { id: reportId },
103	      data: { status: 'READY', filePath, completedAt: new Date() },
104	    });
105	
106	    logger.info({ reportId, reportType: report.reportType }, 'Scheduled report generated');
107	    return updated;
108	  } catch (error) {
109	    await prisma.scheduledReport.update({
110	      where: { id: reportId },
111	      data: { status: 'FAILED' },
112	    });
113	    logger.error({ reportId, error }, 'Failed to generate scheduled report');
114	    throw error;
115	  }
116	}
