1	import crypto from 'crypto';
2	import { config } from '../config';
3	
4	const ALGORITHM = 'aes-256-gcm';
5	const IV_LENGTH = 16;
6	const TAG_LENGTH = 16;
7	
8	function getKey(): Buffer {
9	  const raw = config.encryption.key;
10	  return crypto.createHash('sha256').update(raw).digest();
11	}
12	
13	export function encrypt(plaintext: string): string {
14	  const key = getKey();
15	  const iv = crypto.randomBytes(IV_LENGTH);
16	  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
17	
18	  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
19	  encrypted += cipher.final('hex');
20	
21	  const tag = cipher.getAuthTag();
22	  return `${iv.toString('hex')}:${tag.toString('hex')}:${encrypted}`;
23	}
24	
25	export function decrypt(ciphertext: string): string {
26	  const key = getKey();
27	  const parts = ciphertext.split(':');
28	  if (parts.length !== 3) throw new Error('Invalid encrypted format');
29	
30	  const iv = Buffer.from(parts[0], 'hex');
31	  const tag = Buffer.from(parts[1], 'hex');
32	  const encrypted = parts[2];
33	
34	  const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
35	  decipher.setAuthTag(tag);
36	
37	  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
38	  decrypted += decipher.final('utf8');
39	  return decrypted;
40	}
41	
42	export function maskPhone(phone: string): string {
43	  if (phone.length <= 4) return '****';
44	  return '***-***-' + phone.slice(-4);
45	}
