457	// ─── Schedule Form ───────────────────────────────────────────────────────────
458	const reportTypeOptions = [
459	  { label: 'KPI Summary', value: 'KPI_SUMMARY' },
460	  { label: 'Review Efficiency', value: 'REVIEW_EFFICIENCY' },
461	  { label: 'Inventory Snapshot', value: 'INVENTORY_SNAPSHOT' },
462	];
463	
464	const scheduleForm = ref<{ reportType: string | null; scheduledFor: number | null }>({
465	  reportType: null,
466	  scheduledFor: null,
467	});
468	const scheduleSubmitting = ref(false);
469	
470	async function submitSchedule() {
471	  if (!scheduleForm.value.reportType || !scheduleForm.value.scheduledFor) return;
472	  scheduleSubmitting.value = true;
