1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import { cache } from '../../lib/cache';
4	
5	const CACHE_TTL_MS = 15 * 60 * 1000; // 15 minutes
6	
7	export class SearchService {
8	  async searchProducts(params: {
9	    q?: string;
10	    category?: string;
11	    attributeName?: string;
12	    attributeValue?: string;
13	    sortBy?: string;
14	    sortDir?: string;
15	    page: number;
16	    pageSize: number;
17	    userId?: number;
18	  }) {
19	    const { q, category, attributeName, attributeValue, sortBy = 'name', sortDir = 'asc', page, pageSize, userId } = params;
20	    const skip = (page - 1) * pageSize;
21	
22	    const cacheKey = `search:${q ?? ''}:${category ?? ''}:${attributeName ?? ''}:${attributeValue ?? ''}:${sortBy}:${sortDir}:${page}:${pageSize}`;
23	    const cached = cache.get<any>(cacheKey);
24	    if (cached) return cached;
25	
26	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
27	    const where: any = { isActive: true };
28	    if (category) where.category = category;
29	    if (attributeName && attributeValue) {
30	      where.productAttributes = {
31	        some: { attributeName, attributeValue },
32	      };
33	    }
34	
35	    let items: any[];
36	    let total: number;
37	
38	    if (q && q.trim().length > 0) {
39	      // Use MySQL full-text search
40	      const sanitized = q.trim().replace(/[+\-><\(\)~*\"@]+/g, ' ').trim();
41	      const ftQuery = sanitized.split(/\s+/).filter(Boolean).map((w) => `+${w}*`).join(' ');
42	
43	      // Full-text search returns items sorted by relevance; we need total separately
44	      // Use prisma.$queryRaw for MATCH AGAINST; split on category to avoid nested queryRaw
45	      let rawItems: any[];
46	      let countResult: [{ cnt: bigint }];
47	      if (category) {
48	        rawItems = await prisma.$queryRaw<any[]>`
49	          SELECT i.id, i.name, i.sku, i.category, i.description,
50	                 i.is_lot_controlled, i.unit_of_measure, i.unit_price,
51	                 i.is_active, i.created_at, i.updated_at,
52	                 MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE) AS relevance_score
53	          FROM items i
54	          WHERE i.is_active = 1
55	            AND i.category = ${category}
56	            AND MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE)
57	          ORDER BY relevance_score DESC
58	          LIMIT ${pageSize} OFFSET ${skip}
59	        `;
60	        countResult = await prisma.$queryRaw<[{ cnt: bigint }]>`
61	          SELECT COUNT(*) as cnt FROM items i
62	          WHERE i.is_active = 1
63	            AND i.category = ${category}
64	            AND MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE)
65	        `;
66	      } else {
67	        rawItems = await prisma.$queryRaw<any[]>`
68	          SELECT i.id, i.name, i.sku, i.category, i.description,
69	                 i.is_lot_controlled, i.unit_of_measure, i.unit_price,
70	                 i.is_active, i.created_at, i.updated_at,
71	                 MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE) AS relevance_score
72	          FROM items i
73	          WHERE i.is_active = 1
74	            AND MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE)
75	          ORDER BY relevance_score DESC
76	          LIMIT ${pageSize} OFFSET ${skip}
77	        `;
78	        countResult = await prisma.$queryRaw<[{ cnt: bigint }]>`
79	          SELECT COUNT(*) as cnt FROM items i
80	          WHERE i.is_active = 1
81	            AND MATCH(i.name, i.description, i.sku) AGAINST(${ftQuery} IN BOOLEAN MODE)
82	        `;
83	      }
84	      total = Number(countResult[0].cnt);
85	
86	      // Attach productAttributes
87	      const ids = rawItems.map((r: any) => r.id);
88	      const attrs = ids.length > 0
89	        ? await prisma.productAttribute.findMany({ where: { itemId: { in: ids } } })
90	        : [];
91	      const attrMap = new Map<number, any[]>();
92	      for (const a of attrs) {
93	        if (!attrMap.has(a.itemId)) attrMap.set(a.itemId, []);
94	        attrMap.get(a.itemId)!.push(a);
95	      }
96	      items = rawItems.map((r: any) => ({
97	        ...r,
98	        unitPrice: r.unit_price,
99	        productAttributes: attrMap.get(r.id) ?? [],
100	      }));
101	    } else {
102	      // No full-text — use Prisma ORM query
103	      // eslint-disable-next-line @typescript-eslint/no-explicit-any
104	      const orderBy: any = {};
105	      if (sortBy === 'price') orderBy.unitPrice = sortDir;
106	      else if (sortBy === 'date') orderBy.createdAt = sortDir;
107	      else orderBy.name = sortDir === 'desc' ? 'desc' : 'asc';
108	
109	      [items, total] = await Promise.all([
110	        prisma.item.findMany({
111	          where,
112	          skip,
113	          take: pageSize,
114	          include: { productAttributes: true },
115	          orderBy,
116	        }),
117	        prisma.item.count({ where }),
118	      ]);
119	    }
120	
121	    // Log search term for suggestions
122	    if (q && q.trim().length > 0) {
123	      this.logSearchTerm(q.trim(), total, userId).catch(() => {});
124	    }
125	
126	    const result = { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
127	    cache.set(cacheKey, result, CACHE_TTL_MS);
128	    return result;
129	  }
130	
131	  private async logSearchTerm(term: string, resultsCount: number, userId?: number) {
132	    // Save to search log
133	    await prisma.searchLog.create({
134	      data: { userId: userId ?? null, queryText: term, resultsCount },
135	    }).catch(() => {});
136	
137	    // Upsert suggested term
138	    await prisma.suggestedTerm.upsert({
139	      where: { term },
140	      create: { term, frequency: 1, isTrending: false },
141	      update: { frequency: { increment: 1 } },
142	    }).catch(() => {});
143	  }
144	
145	  async getSuggestions() {
146	    const cacheKey = 'search:suggestions';
147	    const cached = cache.get<any>(cacheKey);
148	    if (cached) return cached;
149	
150	    const terms = await prisma.suggestedTerm.findMany({
151	      orderBy: { frequency: 'desc' },
152	      take: 20,
153	    });
154	
155	    cache.set(cacheKey, terms, CACHE_TTL_MS);
156	    return terms;
157	  }
158	
159	  async getTrending() {
160	    const cacheKey = 'search:trending';
161	    const cached = cache.get<any>(cacheKey);
162	    if (cached) return cached;
163	
164	    const terms = await prisma.suggestedTerm.findMany({
165	      where: { isTrending: true },
166	      orderBy: { frequency: 'desc' },
167	      take: 50,
168	    });
169	
170	    cache.set(cacheKey, terms, CACHE_TTL_MS);
171	    return terms;
172	  }
173	
174	  async getCategories() {
175	    const cacheKey = 'search:categories';
176	    const cached = cache.get<any>(cacheKey);
177	    if (cached) return cached;
178	
179	    const categories = await prisma.item.findMany({
180	      where: { isActive: true },
181	      select: { category: true },
182	      distinct: ['category'],
183	      orderBy: { category: 'asc' },
184	    });
185	
186	    const result = categories.map((c) => c.category);
187	    cache.set(cacheKey, result, CACHE_TTL_MS);
188	    return result;
189	  }
190	
191	  async markTrending(term: string, isTrending: boolean) {
192	    const existing = await prisma.suggestedTerm.findUnique({ where: { term } });
193	    if (!existing) {
194	      throw Object.assign(new Error('Term not found'), { statusCode: 404, code: 'NOT_FOUND' });
195	    }
196	    const updated = await prisma.suggestedTerm.update({
197	      where: { term },
198	      data: { isTrending },
199	    });
200	    cache.delete('search:trending');
201	    cache.delete('search:suggestions');
202	    logger.info({ term, isTrending }, 'Trending status updated');
203	    return updated;
204	  }
205	}
206	
207	export const searchService = new SearchService();
