1	import { Router } from 'express';
2	import { authenticate, authorize } from '../../middleware/auth';
3	import { AuthenticatedRequest, successResponse, errorResponse } from '../../types';
4	import { Response, NextFunction } from 'express';
5	import { searchService } from './search.service';
6	
7	const router = Router();
8	
9	// GET /search/products
10	router.get('/products', authenticate, async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
11	  try {
12	    const page = Math.max(1, parseInt((req.query.page as string) ?? '1', 10));
13	    const pageSize = Math.min(100, Math.max(1, parseInt((req.query.pageSize as string) ?? '20', 10)));
14	
15	    const q = req.query.q as string | undefined;
16	    if (!q || q.trim().length === 0) {
17	      res.status(400).json(errorResponse('VALIDATION_ERROR', 'Search query parameter "q" is required'));
18	      return;
19	    }
20	
21	    const result = await searchService.searchProducts({
22	      q,
23	      category: req.query.category as string | undefined,
24	      attributeName: req.query.attributeName as string | undefined,
25	      attributeValue: req.query.attributeValue as string | undefined,
26	      sortBy: req.query.sortBy as string | undefined,
27	      sortDir: req.query.sortDir as string | undefined,
28	      page,
29	      pageSize,
30	      userId: req.user?.userId,
31	    });
32	
33	    res.json(successResponse(result));
34	  } catch (err: any) {
35	    if (err.statusCode) { res.status(err.statusCode).json(errorResponse(err.code, err.message)); return; }
36	    next(err);
37	  }
38	});
39	
40	// GET /search/categories
41	router.get('/categories', authenticate, async (_req: AuthenticatedRequest, res: Response, next: NextFunction) => {
42	  try {
43	    const categories = await searchService.getCategories();
44	    res.json(successResponse(categories));
45	  } catch (err) {
46	    next(err);
47	  }
48	});
49	
50	// GET /search/suggestions
51	router.get('/suggestions', authenticate, async (_req: AuthenticatedRequest, res: Response, next: NextFunction) => {
52	  try {
53	    const terms = await searchService.getSuggestions();
54	    res.json(successResponse(terms));
55	  } catch (err) {
56	    next(err);
57	  }
58	});
59	
60	// GET /search/trending  (MANAGER, ADMIN)
61	router.get('/trending', authenticate, authorize('MANAGER', 'ADMIN'), async (_req: AuthenticatedRequest, res: Response, next: NextFunction) => {
62	  try {
63	    const terms = await searchService.getTrending();
64	    res.json(successResponse(terms));
65	  } catch (err) {
66	    next(err);
67	  }
68	});
69	
70	// PATCH /search/trending/:term  (ADMIN)
71	router.patch('/trending/:term', authenticate, authorize('ADMIN'), async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
72	  try {
73	    const term = decodeURIComponent(req.params.term as string);
74	    const isTrending = req.body.isTrending === true || req.body.isTrending === 'true';
