38	
39	    it('GET /api/reports/scheduled returns list for authenticated user', async () => {
40	      const res = await api
41	        .get('/api/reports/scheduled')
42	        .set('Authorization', `Bearer ${guestToken}`)
43	        .expect(200);
44	      expect(res.body.success).toBe(true);
45	      expect(Array.isArray(res.body.data)).toBe(true);
46	    });
47	  });
48	
49	  // ─── Schedule report creation ─────────────────────────────────
50	
