53	      const res = await api
54	        .post('/api/reports/schedule')
55	        .set('Authorization', `Bearer ${managerToken}`)
56	        .send({
57	          reportType: 'KPI_SUMMARY',
58	          scheduledFor: new Date(Date.now() - 60000).toISOString(), // past time (due immediately)
59	        })
60	        .expect(201);
61	
62	      expect(res.body.success).toBe(true);
63	      expect(res.body.data.reportType).toBe('KPI_SUMMARY');
64	      expect(res.body.data.status).toBe('PENDING');
65	      expect(res.body.data.id).toBeTypeOf('number');
66	      scheduledReportId = res.body.data.id;
67	    });
68	
69	    it('rejects invalid report type', async () => {
70	      const res = await api
71	        .post('/api/reports/schedule')
72	        .set('Authorization', `Bearer ${managerToken}`)
73	        .send({
74	          reportType: 'INVALID_TYPE',
75	          scheduledFor: new Date().toISOString(),
76	        })
77	        .expect(400);
78	
79	      expect(res.body.success).toBe(false);
80	    });
81	
82	    it('rejects unauthenticated requests', async () => {
83	      await api
84	        .post('/api/reports/schedule')
85	        .send({
86	          reportType: 'KPI_SUMMARY',
87	          scheduledFor: new Date().toISOString(),
88	        })
89	        .expect(401);
90	    });
91	  });
92	
93	  // ─── Process and download ─────────────────────────────────────
94	
95	  describe('Report processing and download', () => {
96	    it('processes a scheduled report to READY', async () => {
97	      const res = await api
98	        .post(`/api/reports/scheduled/${scheduledReportId}/process`)
99	        .set('Authorization', `Bearer ${managerToken}`)
100	        .expect(200);
101	
102	      expect(res.body.success).toBe(true);
103	      expect(res.body.data.status).toBe('READY');
104	      expect(res.body.data.filePath).toBeTruthy();
105	      expect(res.body.data.completedAt).toBeTruthy();
106	    });
107	
108	    it('rejects re-processing an already processed report', async () => {
109	      const res = await api
110	        .post(`/api/reports/scheduled/${scheduledReportId}/process`)
111	        .set('Authorization', `Bearer ${managerToken}`)
112	        .expect(422);
113	
114	      expect(res.body.error.code).toBe('INVALID_STATE');
115	    });
116	
117	    it('downloads a READY report', async () => {
118	      const res = await api
119	        .get(`/api/reports/scheduled/${scheduledReportId}/download`)
120	        .set('Authorization', `Bearer ${managerToken}`)
121	        .expect(200);
122	
123	      expect(res.headers['content-disposition']).toContain('KPI_SUMMARY');
124	    });
125	
126	    it('returns 403 when another user tries to download', async () => {
127	      await api
128	        .get(`/api/reports/scheduled/${scheduledReportId}/download`)
129	        .set('Authorization', `Bearer ${hostToken}`)
130	        .expect(403);
131	    });
132	
133	    it('returns 403 when another user tries to process', async () => {
134	      // Create a new report as manager
135	      const createRes = await api
136	        .post('/api/reports/schedule')
137	        .set('Authorization', `Bearer ${managerToken}`)
138	        .send({
139	          reportType: 'INVENTORY_SNAPSHOT',
140	          scheduledFor: new Date().toISOString(),
141	        })
142	        .expect(201);
143	
144	      // Host (non-admin, non-manager, not owner) tries to process
145	      await api
146	        .post(`/api/reports/scheduled/${createRes.body.data.id}/process`)
147	        .set('Authorization', `Bearer ${hostToken}`)
148	        .expect(403);
149	    });
150	
151	    it('admin can access another user scheduled report', async () => {
152	      const res = await api
153	        .get(`/api/reports/scheduled/${scheduledReportId}/download`)
154	        .set('Authorization', `Bearer ${adminToken}`)
155	        .expect(200);
156	
157	      expect(res.headers['content-disposition']).toContain('KPI_SUMMARY');
158	    });
159	  });
160	
161	  // ─── Format-specific behaviour ───────────────────────────────
162	
163	  describe('Excel format scheduling and download', () => {
164	    let excelReportId: number;
165	
166	    it('creates a scheduled report with format=excel', async () => {
167	      const res = await api
168	        .post('/api/reports/schedule')
169	        .set('Authorization', `Bearer ${managerToken}`)
170	        .send({
171	          reportType: 'INVENTORY_SNAPSHOT',
172	          scheduledFor: new Date(Date.now() - 60000).toISOString(),
173	          format: 'excel',
174	        })
175	        .expect(201);
176	
177	      expect(res.body.success).toBe(true);
178	      expect(res.body.data.format).toBe('excel');
179	      excelReportId = res.body.data.id;
180	    });
181	
182	    it('processes the excel report to READY', async () => {
183	      const res = await api
184	        .post(`/api/reports/scheduled/${excelReportId}/process`)
185	        .set('Authorization', `Bearer ${managerToken}`)
