187	
188	      expect(res.body.data.status).toBe('READY');
189	      expect(res.body.data.filePath).toMatch(/\.xlsx$/);
190	    });
191	
192	    it('downloads excel report with correct content-type and .xlsx filename', async () => {
193	      const res = await api
194	        .get(`/api/reports/scheduled/${excelReportId}/download`)
195	        .set('Authorization', `Bearer ${managerToken}`)
196	        .expect(200);
197	
198	      expect(res.headers['content-disposition']).toMatch(/\.xlsx/);
199	      expect(res.headers['content-type']).toContain(
200	        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
201	      );
202	    });
203	  });
204	
205	  // ─── List includes new scheduled reports ──────────────────────
206	
207	  describe('GET /api/reports/scheduled includes created reports', () => {
208	    it('returns the created scheduled report in list', async () => {
