562	    }
563	
564	    const lines = stockCount!.lines;
565	    const totalSystemQty = lines.reduce((s, l) => s + l.systemQty, 0);
566	    const totalAbsVarianceQty = lines.reduce((s, l) => s + Math.abs(l.varianceQty), 0);
567	    const totalVarianceUsd = lines.reduce((s, l) => s + (l.varianceUsd ? Number(l.varianceUsd) : 0), 0);
568	    const overallVariancePct =
