575	    if (needsApproval) {
576	      return prisma.stockCount.update({
577	        where: { id: stockCountId },
578	        data: {
579	          status: 'PENDING_APPROVAL',
580	          variancePct: overallVariancePct,
581	          varianceUsd: totalVarianceUsd,
582	        },
583	        include: { lines: true, location: true },
584	      });
585	    }
