602	          varianceUsd: totalVarianceUsd,
603	          completedAt: new Date(),
604	        },
605	      });
606	    });
607	
608	    return prisma.stockCount.findUnique({
609	      where: { id: stockCountId },
610	      include: { lines: true, location: true },
611	    });
