100	  it('zero totalSystemQty returns 0% variance (no division by zero)', () => {
101	    const result = computeVarianceResult([{ systemQty: 0, countedQty: 0, unitPrice: 10 }]);
102	    expect(result.overallVariancePct).toBe(0);
103	    expect(result.needsApproval).toBe(false);
104	  });
