146	interface TransferValidation {
147	  valid: boolean;
148	  error?: string;
149	}
150	
151	function validateTransfer(onHand: number, requested: number): TransferValidation {
152	  if (requested <= 0) return { valid: false, error: 'INVALID_QUANTITY' };
153	  if (requested > onHand) return { valid: false, error: 'INSUFFICIENT_STOCK' };
154	  return { valid: true };
