1	import { describe, it, expect } from 'vitest';
2	
3	// ─── Discount calculation (mirrors promotions.service) ───────────────────────
4	
5	function calculateDiscount(
6	  unitPrice: number,
7	  quantity: number,
8	  discountType: string,
9	  discountValue: number
10	): number {
11	  const lineTotal = unitPrice * quantity;
12	  if (discountType === 'PERCENTAGE') {
13	    return Math.round(lineTotal * (discountValue / 100) * 100) / 100;
14	  }
15	  // FIXED_AMOUNT — cap at line total
16	  return Math.min(discountValue, lineTotal);
17	}
18	
19	describe('Promotions - Discount Calculation', () => {
20	  it('calculates percentage discount correctly', () => {
21	    expect(calculateDiscount(100, 2, 'PERCENTAGE', 10)).toBe(20); // 10% of $200
22	  });
23	
24	  it('calculates fixed amount discount correctly', () => {
25	    expect(calculateDiscount(50, 3, 'FIXED_AMOUNT', 25)).toBe(25);
26	  });
27	
28	  it('caps fixed amount discount at line total', () => {
29	    expect(calculateDiscount(10, 2, 'FIXED_AMOUNT', 50)).toBe(20); // max is line total $20
30	  });
31	
32	  it('handles 100% percentage discount', () => {
33	    expect(calculateDiscount(50, 1, 'PERCENTAGE', 100)).toBe(50);
34	  });
35	
36	  it('handles 0% discount', () => {
37	    expect(calculateDiscount(50, 1, 'PERCENTAGE', 0)).toBe(0);
38	  });
39	
40	  it('rounds percentage to 2 decimal places', () => {
41	    // 33.33% of $10 = $3.333 → rounds to $3.33
42	    expect(calculateDiscount(10, 1, 'PERCENTAGE', 33.33)).toBe(3.33);
43	  });
44	});
45	
46	// ─── Promotion priority conflict resolution ───────────────────────────────────
47	
48	interface MockPromotion {
49	  id: number;
50	  priority: number;
51	  discountType: string;
52	  discountValue: number;
53	  exclusionsFrom: { excludedPromotionId: number }[];
54	}
55	
56	function resolveBestPromotion(
57	  promotions: MockPromotion[],
58	  unitPrice: number,
59	  quantity: number,
60	  appliedIds: Set<number>
61	): MockPromotion | null {
62	  let best: MockPromotion | null = null;
63	  let bestSavings = -1;
64	
65	  for (const promo of promotions) {
66	    // Check exclusions
67	    const excludedIds = promo.exclusionsFrom.map((e) => e.excludedPromotionId);
68	    const conflicts = excludedIds.some((id) => appliedIds.has(id));
69	    const appliedExcludesThis = [...appliedIds].some((appliedId) => {
70	      const applied = promotions.find((p) => p.id === appliedId);
71	      return applied?.exclusionsFrom.some((e) => e.excludedPromotionId === promo.id) ?? false;
72	    });
73	    if (conflicts || appliedExcludesThis) continue;
74	
75	    const savings = calculateDiscount(unitPrice, quantity, promo.discountType, promo.discountValue);
76	    if (
77	      best === null ||
78	      promo.priority > best.priority ||
79	      (promo.priority === best.priority && savings > bestSavings)
80	    ) {
81	      best = promo;
82	      bestSavings = savings;
83	    }
84	  }
85	
86	  return best;
87	}
88	
89	describe('Promotions - Conflict Resolution', () => {
90	  it('picks highest priority promotion', () => {
91	    const promos: MockPromotion[] = [
92	      { id: 1, priority: 1, discountType: 'PERCENTAGE', discountValue: 10, exclusionsFrom: [] },
93	      { id: 2, priority: 5, discountType: 'PERCENTAGE', discountValue: 5, exclusionsFrom: [] },
94	    ];
95	    const best = resolveBestPromotion(promos, 100, 1, new Set());
96	    expect(best?.id).toBe(2);
97	  });
98	
99	  it('uses max savings as tiebreaker on equal priority', () => {
100	    const promos: MockPromotion[] = [
101	      { id: 1, priority: 3, discountType: 'PERCENTAGE', discountValue: 10, exclusionsFrom: [] },
102	      { id: 2, priority: 3, discountType: 'PERCENTAGE', discountValue: 20, exclusionsFrom: [] },
103	    ];
104	    const best = resolveBestPromotion(promos, 100, 1, new Set());
105	    expect(best?.id).toBe(2);
