20	
21	function calculateDiscount(
22	  unitPrice: number,
23	  quantity: number,
24	  discountType: string,
25	  discountValue: number
26	): number {
27	  const lineTotal = unitPrice * quantity;
28	  if (discountType === 'PERCENTAGE') {
29	    return Math.round(lineTotal * (discountValue / 100) * 100) / 100;
30	  }
31	  // FIXED_AMOUNT — cap at line total
32	  return Math.min(discountValue, lineTotal);
33	}
