35	function buildDiscountExplanation(promotionName: string, discountType: string, discountValue: number): string {
36	  if (discountType === 'PERCENTAGE') {
37	    return `${promotionName}: ${discountValue}% off`;
38	  }
39	  return `${promotionName}: $${discountValue.toFixed(2)} off`;
40	}
