43	  async listPromotions(isActive?: string, page = 1, pageSize = 20) {
44	    const skip = (page - 1) * pageSize;
45	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
46	    const where: any = {};
47	    if (isActive === 'true') where.isActive = true;
48	    else if (isActive === 'false') where.isActive = false;
49	
50	    const [items, total] = await Promise.all([
51	      prisma.promotion.findMany({
52	        where,
53	        skip,
54	        take: pageSize,
55	        include: {
56	          items: { include: { item: { select: { id: true, name: true, sku: true } } } },
57	          exclusionsFrom: { include: { excludedPromotion: { select: { id: true, name: true } } } },
58	        },
59	        orderBy: [{ priority: 'desc' }, { createdAt: 'desc' }],
60	      }),
61	      prisma.promotion.count({ where }),
62	    ]);
63	
64	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
65	  }
66	
67	  async createPromotion(input: CreatePromotionInput) {
68	    const promotion = await prisma.$transaction(async (tx) => {
69	      const created = await tx.promotion.create({
70	        data: {
71	          name: input.name,
72	          description: input.description ?? null,
73	          discountType: input.discountType,
74	          discountValue: input.discountValue,
75	          effectiveStart: new Date(input.effectiveStart),
76	          effectiveEnd: new Date(input.effectiveEnd),
77	          priority: input.priority ?? 0,
78	          isActive: input.isActive ?? true,
79	          conditions: (input.conditions ?? undefined) as any,
80	        },
81	      });
82	
83	      if (input.itemIds && input.itemIds.length > 0) {
84	        await tx.promotionItem.createMany({
85	          data: input.itemIds.map((itemId) => ({ promotionId: created.id, itemId })),
86	        });
87	      }
88	
89	      if (input.exclusions && input.exclusions.length > 0) {
90	        await tx.promotionExclusion.createMany({
91	          data: input.exclusions.map((excludedId) => ({
92	            promotionId: created.id,
93	            excludedPromotionId: excludedId,
94	          })),
95	        });
96	      }
97	
98	      return created;
99	    });
100	
101	    logger.info({ promotionId: promotion.id, name: promotion.name }, 'Promotion created');
102	    return promotion;
103	  }
104	
105	  async updatePromotion(id: number, input: UpdatePromotionInput) {
106	    const existing = await prisma.promotion.findUnique({ where: { id } });
107	    if (!existing) businessError('NOT_FOUND', 'Promotion not found', 404);
108	
109	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
110	    const data: any = {};
111	    if (input.name !== undefined) data.name = input.name;
112	    if (input.description !== undefined) data.description = input.description;
113	    if (input.discountType !== undefined) data.discountType = input.discountType;
114	    if (input.discountValue !== undefined) data.discountValue = input.discountValue;
115	    if (input.effectiveStart !== undefined) data.effectiveStart = new Date(input.effectiveStart);
116	    if (input.effectiveEnd !== undefined) data.effectiveEnd = new Date(input.effectiveEnd);
117	    if (input.priority !== undefined) data.priority = input.priority;
118	    if (input.isActive !== undefined) data.isActive = input.isActive;
119	
120	    const updated = await prisma.promotion.update({ where: { id }, data });
121	    logger.info({ promotionId: id }, 'Promotion updated');
