124	
125	  async checkout(input: CheckoutInput) {
126	    const now = new Date();
127	
128	    // Fetch all active promotions valid right now, highest priority first
129	    const activePromotions = await prisma.promotion.findMany({
130	      where: {
131	        isActive: true,
132	        effectiveStart: { lte: now },
133	        effectiveEnd: { gte: now },
134	      },
135	      include: {
136	        items: { select: { itemId: true } },
137	        exclusionsFrom: { select: { excludedPromotionId: true } },
138	      },
139	      orderBy: [{ priority: 'desc' }, { discountValue: 'desc' }],
140	    });
141	
142	    // Fetch item prices
143	    const itemIds = input.items.map((i) => i.itemId);
144	    const items = await prisma.item.findMany({
145	      where: { id: { in: itemIds }, isActive: true },
146	      select: { id: true, name: true, unitPrice: true },
147	    });
148	
149	    const itemMap = new Map(items.map((i) => [i.id, i]));
150	
151	    // Validate all items exist
152	    for (const line of input.items) {
153	      if (!itemMap.has(line.itemId)) {
154	        businessError('NOT_FOUND', `Item #${line.itemId} not found or not active`, 404);
155	      }
156	    }
157	
158	    const lineResults: LineResult[] = [];
159	    let orderTotal = 0;
160	    let totalDiscount = 0;
161	
162	    // Track which promotions have been applied (for exclusion logic)
163	    const appliedPromotionIds = new Set<number>();
164	
165	    // For each line item, find the best applicable promotion
166	    for (const line of input.items) {
167	      const item = itemMap.get(line.itemId)!;
168	      const unitPrice = Number(item.unitPrice ?? 0);
169	      const originalTotal = unitPrice * line.quantity;
170	
171	      let bestPromotion: (typeof activePromotions)[0] | null = null;
172	      let bestSavings = 0;
173	
174	      for (const promo of activePromotions) {
175	        // Skip if this promo excludes one already applied
176	        const excludedIds = promo.exclusionsFrom.map((e) => e.excludedPromotionId);
177	        const conflictsWithApplied = excludedIds.some((eid) => appliedPromotionIds.has(eid));
178	        // Also check reverse: if a previously applied promo excludes this one
179	        const alreadyAppliedExcludesThis = [...appliedPromotionIds].some((appliedId) => {
180	          const appliedPromo = activePromotions.find((p) => p.id === appliedId);
181	          return appliedPromo?.exclusionsFrom.some((e) => e.excludedPromotionId === promo.id) ?? false;
182	        });
183	        if (conflictsWithApplied || alreadyAppliedExcludesThis) continue;
184	
185	        // Check if promo applies to this item (empty items list = applies to all)
186	        const promoItemIds = promo.items.map((pi) => pi.itemId);
187	        if (promoItemIds.length > 0 && !promoItemIds.includes(line.itemId)) continue;
188	
189	        const savings = calculateDiscount(unitPrice, line.quantity, promo.discountType, Number(promo.discountValue));
190	        // Higher priority wins; on tie pick max savings
191	        if (
192	          bestPromotion === null ||
193	          promo.priority > bestPromotion.priority ||
194	          (promo.priority === bestPromotion.priority && savings > bestSavings)
195	        ) {
196	          bestPromotion = promo;
197	          bestSavings = savings;
198	        }
199	      }
200	
201	      const discountAmount = bestSavings;
202	      const finalTotal = originalTotal - discountAmount;
203	
204	      if (bestPromotion) {
205	        appliedPromotionIds.add(bestPromotion.id);
206	
207	        // Persist applied promotion record
208	        await prisma.appliedPromotion.create({
209	          data: {
210	            itemId: line.itemId,
211	            promotionId: bestPromotion.id,
212	            originalPrice: originalTotal,
213	            discountAmount,
214	            finalPrice: finalTotal,
215	            reasonApplied: buildDiscountExplanation(
216	              bestPromotion.name,
217	              bestPromotion.discountType,
218	              Number(bestPromotion.discountValue)
219	            ),
220	          },
221	        });
222	      }
223	
224	      lineResults.push({
225	        itemId: line.itemId,
226	        quantity: line.quantity,
227	        unitPrice,
228	        originalTotal,
229	        discountAmount,
230	        finalTotal,
231	        promotionId: bestPromotion?.id ?? null,
232	        promotionName: bestPromotion?.name ?? null,
233	        discountExplanation: bestPromotion
234	          ? buildDiscountExplanation(bestPromotion.name, bestPromotion.discountType, Number(bestPromotion.discountValue))
235	          : null,
236	      });
237	
238	      orderTotal += finalTotal;
239	      totalDiscount += discountAmount;
240	    }
241	
242	    const originalOrderTotal = lineResults.reduce((s, l) => s + l.originalTotal, 0);
243	
244	    logger.info({ itemCount: input.items.length, totalDiscount, orderTotal }, 'Checkout calculated');
245	
246	    return {
247	      lines: lineResults,
248	      originalOrderTotal,
249	      totalDiscount,
250	      orderTotal,
251	    };
252	  }
253	}
