16	export async function filterContent(text: string): Promise<{ clean: boolean; flaggedWords: string[] }> {
17	  const sensitiveWords = await loadSensitiveWords();
18	  const normalized = text.toLowerCase().replace(/[^a-z0-9\s]/g, '');
19	  const flaggedWords: string[] = [];
20	
21	  for (const word of sensitiveWords) {
22	    // Use word-boundary matching to avoid false positives (e.g., "class" matching "ass")
23	    const pattern = new RegExp(`\\b${word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
24	    if (pattern.test(normalized)) {
25	      flaggedWords.push(word);
26	    }
27	  }
28	
29	  return {
30	    clean: flaggedWords.length === 0,
31	    flaggedWords,
32	  };
33	}
